mapper.select:
SELECT * FROM ( SELECT ROW_NUMBER() OVER (ORDER BY A1.PRO_ID DESC) AS RNUM , COALESCE(A1.PRO_ID, '') AS PRO_ID , COALESCE(A1.PRO_GB, '') AS PRO_GB , COALESCE(A1.PRO_TYPE, '') AS PRO_TYPE , CASE WHEN A1.PRO_TYPE = '01' THEN '교육' WHEN A1.PRO_TYPE = '02' THEN '지원사업' WHEN A1.PRO_TYPE = '03' THEN '홍보' ELSE '' END AS PRO_TYPE_NM , COALESCE(A1.REQ_GB, '') AS REQ_GB , COALESCE(A1.PRO_NM, '') AS PRO_NM , COALESCE(A1.PRO_TARGET_NM, '') AS PRO_TARGET_NM , COALESCE(A1.ETC_NM, '') AS ETC_NM , COALESCE((SELECT CODE_NM FROM LETTCCMMNDETAILCODE WHERE CODE_ID = 'EDR007' AND CODE = A1.PRO_DEPA), COALESCE(A1.PRO_DEPA, '')) AS PRO_DEPA , COALESCE(A1.EDU_GB, 'N') AS EDU_GB , COALESCE(A1.PRO_TARGET, '') AS PRO_TARGET , COALESCE(A1.BASIC_YN, 'N') AS BASIC_YN , COALESCE(A1.POOR_YN, 'N') AS POOR_YN , COALESCE(A1.SINGLE_YN, 'N') AS SINGLE_YN , COALESCE(DATE_FORMAT(A1.REC_FROM_DD, '%Y%m%d'), '') AS REC_FROM_DD , COALESCE(DATE_FORMAT(A1.REC_TO_DD, '%Y%m%d'), '') AS REC_TO_DD , COALESCE(A1.REC_CNT, 0) AS REC_CNT , COALESCE(A1.PRO_SUM, '') AS PRO_SUM , COALESCE(A1.PRO_DESC, '') AS PRO_DESC , COALESCE(A1.PRO_FILE_ID, '') AS PRO_FILE_ID , COALESCE(A1.FILE_ID, '') AS FILE_ID , COALESCE(A1.RUN_STA, '') AS RUN_STA , CASE WHEN A1.RUN_STA = '01' THEN '접수예정' WHEN A1.RUN_STA = '02' THEN '접수중' WHEN A1.RUN_STA = '04' THEN '접수마감' WHEN A1.RUN_STA = '99' THEN '취소' ELSE '' END AS RUN_STA_NM FROM ARTPROM A1 WHERE 1=1 AND A1.STTUS_CODE = 'A'
AND UPPER(TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(COALESCE(A1.REQ_GB, ''), '|', 4), '|', -1))) = 'Y'
AND A1.PRO_GB = #{searchProGb}
AND A1.REC_FROM_DD <= DATE_FORMAT(#{searchRecToDd}, '%Y-%m-%d') AND A1.REC_TO_DD >= DATE_FORMAT(#{searchRecFromDd}, '%Y-%m-%d')
AND A1.RUN_STA = #{searchRunSta}
AND A1.PRO_NM LIKE CONCAT('%', #{searchProNm}, '%')
) A0 LIMIT #{lengthPage} OFFSET #{startIndex}

SELECT COUNT(1) FROM ARTPROM A1 WHERE 1=1 AND A1.STTUS_CODE = 'A'
AND UPPER(TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(COALESCE(A1.REQ_GB, ''), '|', 4), '|', -1))) = 'Y'
AND A1.PRO_GB = #{searchProGb}
AND A1.REC_FROM_DD <= DATE_FORMAT(#{searchRecToDd}, '%Y-%m-%d') AND A1.REC_TO_DD >= DATE_FORMAT(#{searchRecFromDd}, '%Y-%m-%d')
AND A1.RUN_STA = #{searchRunSta}
AND A1.PRO_NM LIKE CONCAT('%', #{searchProNm}, '%')

SELECT * FROM ( SELECT ROW_NUMBER() OVER (ORDER BY A1.PRO_ID DESC) AS RNUM , COALESCE(A1.PRO_ID, '') AS PRO_ID , COALESCE(A1.PRO_GB, '') AS PRO_GB , COALESCE(A1.PRO_TYPE, '') AS PRO_TYPE , CASE WHEN A1.PRO_TYPE = '01' THEN '교육' WHEN A1.PRO_TYPE = '02' THEN '지원사업' WHEN A1.PRO_TYPE = '03' THEN '홍보' ELSE '' END AS PRO_TYPE_NM , COALESCE(A1.REQ_GB, '') AS REQ_GB , COALESCE(A1.PRO_NM, '') AS PRO_NM , COALESCE(A1.PRO_TARGET_NM, '') AS PRO_TARGET_NM , COALESCE(A1.ETC_NM, '') AS ETC_NM , COALESCE((SELECT CODE_NM FROM LETTCCMMNDETAILCODE WHERE CODE_ID = 'EDR007' AND CODE = A1.PRO_DEPA), COALESCE(A1.PRO_DEPA, '')) AS PRO_DEPA , COALESCE(A1.EDU_GB, 'N') AS EDU_GB , COALESCE(A1.PRO_TARGET, '') AS PRO_TARGET , COALESCE(A1.BASIC_YN, 'N') AS BASIC_YN , COALESCE(A1.POOR_YN, 'N') AS POOR_YN , COALESCE(A1.SINGLE_YN, 'N') AS SINGLE_YN , COALESCE(DATE_FORMAT(A1.REC_FROM_DD, '%Y%m%d'), '') AS REC_FROM_DD , COALESCE(DATE_FORMAT(A1.REC_TO_DD, '%Y%m%d'), '') AS REC_TO_DD , COALESCE(A1.REC_CNT, 0) AS REC_CNT , COALESCE(A1.PRO_SUM, '') AS PRO_SUM , COALESCE(A1.PRO_DESC, '') AS PRO_DESC , COALESCE(A1.PRO_FILE_ID, '') AS PRO_FILE_ID , COALESCE(A1.FILE_ID, '') AS FILE_ID , COALESCE(A1.RUN_STA, '') AS RUN_STA , CASE WHEN A1.RUN_STA = '01' THEN '접수예정' WHEN A1.RUN_STA = '02' THEN '접수중' WHEN A1.RUN_STA = '04' THEN '접수마감' WHEN A1.RUN_STA = '99' THEN '취소' ELSE '' END AS RUN_STA_NM FROM ARTPROM A1 WHERE 1=1 AND A1.STTUS_CODE = 'A'
AND UPPER(TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(COALESCE(A1.REQ_GB, ''), '|', 4), '|', -1))) = 'Y'
AND A1.PRO_GB = #{searchProGb}
AND A1.REC_FROM_DD <= DATE_FORMAT(#{searchRecToDd}, '%Y-%m-%d') AND A1.REC_TO_DD >= DATE_FORMAT(#{searchRecFromDd}, '%Y-%m-%d')
AND A1.RUN_STA = #{searchRunSta}
AND A1.PRO_NM LIKE CONCAT('%', #{searchProNm}, '%')
) A0

mapper.update:
UPDATE ARTPROM
   SET PRO_FILE_ID = ''
 WHERE PRO_ID = #{proId}

UPDATE ARTPROM
   SET FILE_ID = ''
 WHERE PRO_ID = #{proId}
